const Variants = ({ onClick }) => {
  const buttonComponents = Object.values(buttonTypes)
  const fullPermutations = [
    { size: 'sm' as const },
    {},
    { size: 'lg' as const },
    { disabled: true },
    { 'aria-pressed': true },
    { isLoading: true, size: 'sm' as const },
    { isLoading: true },
    { isLoading: true, size: 'lg' as const },
    { isFullWidth: true, size: 'sm' as const },
    { isFullWidth: true },
    { isFullWidth: true, size: 'lg' as const },
    { isLoading: true, isFullWidth: true },
    { isMenuButton: true, size: 'sm' as const },
    { isMenuButton: true },
    { isMenuButton: true, size: 'lg' as const },
    { isMenuButton: true, isFullWidth: true, size: 'sm' as const },
    { isMenuButton: true, isFullWidth: true },
    { isMenuButton: true, isFullWidth: true, size: 'lg' as const },
  ]
  const miniPermutations = [
    { size: 'sm' as const },
    {},
    { size: 'lg' as const },
    { disabled: true },
    { isFullWidth: true },
  ]

  return (
    <div className={variationsGrid}>
      {/* Labels */}
      {buttonComponents.map((ButtonType, i) => {
        return <code key={i}>{Object.keys(buttonTypes)[i]}</code>
      })}
      <hr className={variationsRule} />

      {/* Full prop permutations */}
      {fullPermutations.map((prop) =>
        buttonComponents.map((ButtonType, i) => {
          const lastProps = i === buttonComponents.length - 1 ? { isPlain: true } : {}
          return (
            <ButtonType key={i} onClick={onClick} {...lastProps} {...prop}>
              Example
            </ButtonType>
          )
        })
      )}
      <hr className={variationsRule} />

      {/* Focus state */}
      {buttonComponents.map((ButtonType, i) => {
        const lastProps = i === buttonComponents.length - 1 ? { isPlain: true } : {}
        return (
          <ButtonType
            key={i}
            onClick={onClick}
            {...lastProps}
            className={baseButton.classNames.variants.hasFocus.true}
          >
            Example
          </ButtonType>
        )
      })}
      <hr className={variationsRule} />

      {/* With icons */}
      {miniPermutations.map((prop) =>
        buttonComponents.map((ButtonType, i) => {
          const lastProps = i === buttonComponents.length - 1 ? { isPlain: true } : {}
          return (
            <ButtonType key={i} onClick={onClick} {...lastProps} {...prop}>
              <StarIcon aria-hidden />
              Example
            </ButtonType>
          )
        })
      )}
    </div>
  )
};

