const Variants = ({ onClick }) => {
  const iconButtonComponents = Object.values(iconButtonTypes)
  const variants = [
    { state: 'Medium Size', props: {} },
    { state: 'IsLoading Medium', props: { isLoading: true } },
    { state: 'Small Size', props: { size: 'sm' as const } },
    { state: 'IsLoading Small', props: { isLoading: true, size: 'sm' as const } },
    { state: 'Large Size', props: { size: 'lg' as const } },
    { state: 'IsLoading Large', props: { isLoading: true, size: 'lg' as const } },
    { state: 'Disabled', props: { disabled: true } },
    { state: 'Focus', props: { className: baseButton.classNames.variants.hasFocus.true } },
    { state: 'IsMenuButton', props: { isMenuButton: true } },
    { state: 'IsMenuButton expanded', props: { isMenuButton: true, 'aria-expanded': true } },
  ]

  return (
    <div className={variationsGrid}>
      {/* Labels */}
      {
        <code>
          <b>States</b>
