      })}
      <hr className={variationsRule} />

      {/* Variants */}
      {variants.map((variant) => [
        <code>{variant.state}</code>,
        ...iconButtonComponents.map((ButtonType, i) => {
          return (
            <ButtonType aria-label={ButtonType.toString()} key={i} onClick={onClick} {...variant.props}>
