const Sorting = () => {
  const initData = bigCrocData(1)
  const [data, setData] = React.useState(initData)
  const [appliedSort, setAppliedSort] = useState<AppliedSort>()

  useEffect(() => {
    if (appliedSort) {
      const sortedData = [...data].sort((a, b) => {
        const key = appliedSort.column as keyof typeof a
        if (a[key] < b[key]) return appliedSort.direction === 'ascending' ? -1 : 1
        if (a[key] > b[key]) return appliedSort.direction === 'ascending' ? 1 : -1
        return 0
      })
      setData(sortedData)
    } else {
      setData(initData)
    }
  }, [appliedSort])

  return (
    <DataTable appliedSort={appliedSort} onSort={setAppliedSort}>
      <DataTable.Table aria-label="A list of crocodile facts">
        <DataTable.Header>
          <DataTable.Column width="1fr" allowsSorting key="id">
            ID
          </DataTable.Column>
          <DataTable.Column width="2fr" minWidth={110} allowsSorting key="species">
            Species or common name of crocodilian
          </DataTable.Column>
          <DataTable.Column width="1fr" align="right" allowsSorting key="lengthCm">
            Length
          </DataTable.Column>
          <DataTable.Column width="1fr" align="right" allowsSorting key="weightKg">
            Weight
          </DataTable.Column>
          <DataTable.Column width="4fr" minWidth={240}>
            Habitat
          </DataTable.Column>
        </DataTable.Header>
        <DataTable.Body>
          {data.map((croc) => (
            <DataTable.Row key={croc.id}>
              <DataTable.Cell>{croc.id}</DataTable.Cell>
              <DataTable.Cell>{croc.species}</DataTable.Cell>
              <DataTable.Cell>{croc.lengthCm}cm</DataTable.Cell>
              <DataTable.Cell>{croc.weightKg}kg</DataTable.Cell>
              <DataTable.Cell>{croc.habitat}</DataTable.Cell>
            </DataTable.Row>
          ))}
        </DataTable.Body>
      </DataTable.Table>
    </DataTable>
  )
};

const AsyncLoading = () => {
  const [isLoading, setIsLoading] = useState(false)
  const [appliedSort, setAppliedSort] = useState<AppliedSort>()
  const [data, setData] = useState<Crocodile[]>([])

  const fetchData = async (sort?: AppliedSort): Promise<Crocodile[]> =>
    new Promise((resolve) => {
      setTimeout(() => {
        if (!sort) {
          resolve(bigCrocData(8))
          return
        }

        const sortedData = [...data].sort((a, b) => {
          const key = sort.column as keyof typeof a
          if (a[key] < b[key]) return sort.direction === 'ascending' ? -1 : 1
          if (a[key] > b[key]) return sort.direction === 'ascending' ? 1 : -1
          return 0
        })
        resolve(sortedData)
      }, 1500)
    })

  useEffect(() => {
    setIsLoading(true)
    fetchData()
      .then(setData)
      .finally(() => setIsLoading(false))
  }, [])

  useEffect(() => {
    setIsLoading(true)
    fetchData(appliedSort)
      .then(setData)
      .finally(() => setIsLoading(false))
  }, [appliedSort])

  return (
    <DataTable appliedSort={appliedSort} onSort={setAppliedSort}>
      <DataTable.Table aria-label="A list of crocodile facts">
        <DataTable.Header>
          <DataTable.Column allowsSorting key="id">
            ID
          </DataTable.Column>
          <DataTable.Column allowsSorting key="species">
            Species or common name of crocodilian
          </DataTable.Column>
          <DataTable.Column allowsSorting key="lengthCm" align="right">
            Length
          </DataTable.Column>
          <DataTable.Column allowsSorting key="weightKg" align="right">
            Weight
          </DataTable.Column>
        </DataTable.Header>
        <DataTable.Body>
          {isLoading ? (
            <DataTable.LoadingState rowCount={data.length || 5} />
          ) : (
            data.map((croc) => (
              <DataTable.Row key={croc.id}>
                <DataTable.Cell>{croc.id}</DataTable.Cell>
                <DataTable.Cell>{croc.species}</DataTable.Cell>
                <DataTable.Cell>{croc.lengthCm}cm</DataTable.Cell>
                <DataTable.Cell>{croc.weightKg}kg</DataTable.Cell>
              </DataTable.Row>
            ))
          )}
        </DataTable.Body>
      </DataTable.Table>
    </DataTable>
  )
};

const RenderProps = () => {
  type DataTableColumn = {
    key: string
    label: React.ReactNode
    align?: 'left' | 'right'
    isRowHeader?: boolean
  }

  const columns: DataTableColumn[] = [
    { key: 'id', label: 'ID', isRowHeader: true },
    { key: 'species', label: 'Species' },
    { key: 'lengthCm', label: 'Length', align: 'right' },
    { key: 'weightKg', label: 'Weight', align: 'right' },
  ]

  return (
    <DataTable>
      <DataTable.Table aria-label="A list of crocodile facts">
        <DataTable.Header columns={columns}>
          {(column: DataTableColumn) => (
            <DataTable.Column isRowHeader={column.isRowHeader} align={column.align}>
              {column.label}
            </DataTable.Column>
          )}
        </DataTable.Header>
        <DataTable.Body items={crocodileData}>
          {(item) => (
            <DataTable.Row>
              {(columnKey: number | string) => (
                <DataTable.Cell>{item[columnKey as keyof typeof item]}</DataTable.Cell>
              )}
            </DataTable.Row>
          )}
        </DataTable.Body>
      </DataTable.Table>
    </DataTable>
  )
};

const ErrorBoundary = () => {
  const fallback = (
    <>
      <Heading level={4}>Something went wrong</Heading>
      <Text style={{ marginTop: vars.global.size['1x'] }}>We couldn't load your data. </Text>
