  )
};

const ProgrammaticDismissal = ({ onDismiss }) => {
  const closeStack: string[] = []
  let i = 1

  const handleOpen = () => {
    closeStack.push(
      showToast({
        content: `Test message #${i++}`,
        isDismissible: true,
        onDismiss,
      })
    )
  }

  const handleClose = () => {
    closeToast(closeStack.pop()!)
  }

  return (
    <>
      <Toaster />
      <div className={storyStack}>
        <Button onClick={handleOpen}>Show a Toast</Button>
        <Button onClick={handleClose}>Close last Toast</Button>
      </div>
    </>
  )
};

